mapper.update:
UPDATE FWK_PROPERTY
SET CUR_VERSION = NVL(CUR_VERSION, 0) + 1
WHERE PROPERTY_GROUP_ID = #{propertyGroupId}

mapper.select:
SELECT MAX(VERSION)
FROM FWK_PROPERTY_HISTORY
WHERE PROPERTY_GROUP_ID = #{propertyGroupId}

mapper.insert:
INSERT INTO FWK_PROPERTY_HISTORY ( PROPERTY_GROUP_ID, PROPERTY_ID, VERSION, PROPERTY_NAME, PROPERTY_DESC, DATA_TYPE, VALID_DATA, DEFAULT_VALUE, REASON, LAST_UPDATE_USER_ID, LAST_UPDATE_DTIME ) SELECT A.* FROM (
SELECT #{item.propertyGroupId}, #{item.propertyId}, #{version}, #{item.propertyName}, #{item.propertyDesc}, #{item.dataType, jdbcType=VARCHAR}, #{item.validData, jdbcType=VARCHAR}, #{item.defaultValue, jdbcType=VARCHAR}, #{reason, jdbcType=VARCHAR}, #{lastUpdateUserId}, #{lastUpdateDtime} FROM DUAL
) A

INSERT INTO FWK_PROPERTY ( PROPERTY_GROUP_ID, PROPERTY_ID, PROPERTY_NAME, PROPERTY_DESC, DATA_TYPE, VALID_DATA, DEFAULT_VALUE, LAST_UPDATE_USER_ID, LAST_UPDATE_DTIME, CUR_VERSION ) SELECT A.* FROM (
SELECT #{item.propertyGroupId}, #{item.propertyId}, #{item.propertyName, jdbcType=VARCHAR}, #{item.propertyDesc, jdbcType=VARCHAR}, #{item.dataType, jdbcType=VARCHAR}, #{item.validData, jdbcType=VARCHAR}, #{item.defaultValue, jdbcType=VARCHAR}, #{lastUpdateUserId}, #{lastUpdateDtime}, #{item.version} FROM DUAL
) A
